  1→import { RecordId } from "surrealdb";
  2→import type { ExtractedEntity, ExtractedRelationship, OnboardingAction, OnboardingSeedItem } from "../../shared/contracts";
  3→import { buildExtractionComponentBlock } from "../extraction/components";
  4→import { loadAssistantConversationContext, loadConversationGraphContext, loadExtractionConversationContext } from "../extraction/context-loaders";
  5→import { ingestAttachment } from "../extraction/document-ingestion";
  6→import { persistEmbeddings } from "../extraction/embedding-writeback";
  7→import { extractStructuredGraph } from "../extraction/extract-graph";
  8→import { appendExtractedTools, persistExtractionOutput } from "../extraction/persist-extraction";
  9→import type { ConversationRow, GraphEntityRecord, IncomingAttachment, SourceRecord, WorkspaceRow } from "../extraction/types";
 10→import { elapsedMs, logError, logInfo, userFacingError } from "../http/observability";
 11→import { transitionOnboardingState } from "../onboarding/onboarding-state";
 12→import { generateOnboardingAssistantReply } from "../onboarding/onboarding-reply";
 13→import type { ServerDependencies } from "../runtime/types";
 14→import { runGraphAwareChat } from "./handler";
 15→import { getWorkspaceOwnerRecord } from "../graph/queries";
 16→import { refreshConversationTouchedBy, maybeUpgradeConversationTitle } from "../workspace/conversation-sidebar";
 17→
 18→export async function processChatMessage(input: {
 19→  deps: ServerDependencies;
 20→  conversationId: string;
 21→  messageId: string;
 22→  workspaceRecord: RecordId<"workspace", string>;
 23→  userMessageRecord: RecordId<"message", string>;
 24→  userText: string;
 25→  attachment?: IncomingAttachment;
 26→  onboardingAction?: OnboardingAction;
 27→}): Promise<void> {
 28→  const startedAt = performance.now();
 29→  logInfo("chat.message.process.execution.started", "Chat message processing execution started", {
 30→    conversationId: input.conversationId,
 31→    messageId: input.messageId,
 32→    workspaceId: input.workspaceRecord.id as string,
 33→    hasAttachment: input.attachment !== undefined,
 34→  });
 35→
 36→  try {
 37→    const now = new Date();
 38→    const conversationRecord = new RecordId("conversation", input.conversationId);
 39→    const workspace = await input.deps.surreal.select<WorkspaceRow>(input.workspaceRecord);
 40→    if (!workspace) {
 41→      throw new Error("workspace not found");
 42→    }
 43→
 44→    const conversation = await input.deps.surreal.select<ConversationRow>(conversationRecord);
 45→    if (!conversation) {
 46→      throw new Error("conversation not found");
 47→    }
 48→
 49→    const assistantContextRows = await loadAssistantConversationContext(input.deps.surreal, input.conversationId);
 50→    const extractionConversationContext = await loadExtractionConversationContext({
 51→      surreal: input.deps.surreal,
 52→      conversationId: input.conversationId,
 53→      currentMessageRecord: input.userMessageRecord,
 54→    });
 55→    const extractionGraphContext = await loadConversationGraphContext(input.deps.surreal, input.conversationId, 60);
 56→    const persistedEntities: ExtractedEntity[] = [];
 57→    const persistedRelationships: ExtractedRelationship[] = [];
 58→    const seedItems: OnboardingSeedItem[] = [];
 59→    const embeddingTargets: Array<{ record: GraphEntityRecord; text: string }> = [];
 60→    const extractedTools: string[] = [];
 61→    const unresolvedAssigneeNames = new Set<string>();
 62→
 63→    if (input.attachment) {
 64→      const ingestion = await ingestAttachment({
 65→        surreal: input.deps.surreal,
 66→        extractionModel: input.deps.extractionModel,
 67→        embeddingModel: input.deps.embeddingModel,
 68→        embeddingDimension: input.deps.config.embeddingDimension,
 69→        extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
 70→        extractionModelId: input.deps.config.extractionModelId,
 71→        workspaceRecord: input.workspaceRecord,
 72→        conversationRecord,
 73→        userMessageRecord: input.userMessageRecord,
 74→        attachment: input.attachment,
 75→        now,
 76→      });
 77→
 78→      persistedEntities.push(...ingestion.entities);
 79→      persistedRelationships.push(...ingestion.relationships);
 80→      seedItems.push(...ingestion.seeds);
 81→      embeddingTargets.push(...ingestion.embeddingTargets);
 82→      extractedTools.push(...ingestion.tools);
 83→      for (const unresolvedName of ingestion.unresolvedAssigneeNames) {
 84→        unresolvedAssigneeNames.add(unresolvedName);
 85→      }
 86→    }
 87→
 88→    const textExtraction = await extractStructuredGraph({
 89→      extractionModel: input.deps.extractionModel,
 90→      conversationHistory: extractionConversationContext.conversationHistory,
 91→      currentMessage: extractionConversationContext.currentMessage,
 92→      graphContext: extractionGraphContext,
 93→      sourceText: input.userText,
 94→      onboarding: !workspace.onboarding_complete,
 95→    });
 96→
 97→    const textPersistence = await persistExtractionOutput({
 98→      surreal: input.deps.surreal,
 99→      embeddingModel: input.deps.embeddingModel,
100→      embeddingDimension: input.deps.config.embeddingDimension,
101→      extractionModelId: input.deps.config.extractionModelId,
102→      extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
103→      workspaceRecord: input.workspaceRecord,
104→      sourceRecord: input.userMessageRecord as SourceRecord,
105→      sourceKind: "message",
106→      sourceLabel: input.userText.slice(0, 140),
107→      promptText: input.userText,
108→      output: textExtraction,
109→      sourceMessageRecord: input.userMessageRecord,
110→      extractionHistoryMessageIds: extractionConversationContext.conversationHistory.map((row) => row.id.id as string),
111→      now,
112→    });
113→
114→    persistedEntities.push(...textPersistence.entities);
115→    persistedRelationships.push(...textPersistence.relationships);
116→    seedItems.push(...textPersistence.seeds);
117→    embeddingTargets.push(...textPersistence.embeddingTargets);
118→    extractedTools.push(...textPersistence.tools);
119→    for (const unresolvedName of textPersistence.unresolvedAssigneeNames) {
120→      unresolvedAssigneeNames.add(unresolvedName);
121→    }
122→
123→    const dedupedTools = [...new Set(extractedTools.map((tool) => tool.trim()).filter((tool) => tool.length > 0))];
124→    await appendExtractedTools(input.deps.surreal, input.workspaceRecord, extractedTools, now);
125→
126→    await refreshConversationTouchedBy(input.deps.surreal, conversationRecord);
127→    await maybeUpgradeConversationTitle(input.deps.surreal, conversationRecord);
128→
129→    const onboardingBefore = workspace.onboarding_complete
130→      ? "complete"
131→      : workspace.onboarding_summary_pending
132→        ? "summary_pending"
133→        : "active";
134→
135→    const onboardingAfter = await transitionOnboardingState({
136→      surreal: input.deps.surreal,
137→      workspaceRecord: input.workspaceRecord,
138→      workspace,
139→      onboardingAction: input.onboardingAction,
140→      now,
141→    });
142→
143→    let assistantText = "";
144→    let assistantSuggestions: string[] = [];
145→    const unresolvedAssigneeSuggestions = [...unresolvedAssigneeNames].map(
146→      (name) => `You mentioned ${name} - want to add them to workspace people?`,
147→    );
148→
149→    if (onboardingAfter === "complete") {
150→      const workspaceOwnerRecord = await getWorkspaceOwnerRecord({
151→        surreal: input.deps.surreal,
152→        workspaceRecord: input.workspaceRecord,
153→      });
154→
155→      const graphAwareResponse = await runGraphAwareChat({
156→        surreal: input.deps.surreal,
157→        model: input.deps.assistantModel,
158→        embeddingModel: input.deps.embeddingModel,
159→        embeddingDimension: input.deps.config.embeddingDimension,
160→        extractionModelId: input.deps.config.extractionModelId,
161→        conversationRecord,
162→        workspaceRecord: input.workspaceRecord,
163→        currentMessageRecord: input.userMessageRecord,
164→        latestUserText: input.userText,
165→        ...(workspaceOwnerRecord ? { workspaceOwnerRecord } : {}),
166→        messages: assistantContextRows.map((row) => ({
167→          role: row.role,
168→          text: row.text,
169→        })),
170→        onToken: async (token) => {
171→          input.deps.sse.emitEvent(input.messageId, {
172→            type: "token",
173→            messageId: input.messageId,
174→            token,
175→          });
176→        },
177→      });
178→
179→      assistantText = graphAwareResponse.text.trim();
180→    } else {
181→      const assistantReply = await generateOnboardingAssistantReply({
182→        assistantModel: input.deps.assistantModel,
183→        surreal: input.deps.surreal,
184→        onboardingState: onboardingAfter,
185→        contextRows: assistantContextRows,
186→        latestUserText: input.userText,
187→        workspaceRecord: input.workspaceRecord,
188→        latestEntities: persistedEntities.map((entity) => ({
189→          kind: entity.kind,
190→          text: entity.text,
191→          confidence: entity.confidence,
192→        })),
193→        latestTools: dedupedTools,
194→      });
195→
196→      assistantText = assistantReply.message.trim();
197→      assistantSuggestions = assistantReply.suggestions;
198→
199→      for (const token of assistantText.split(" ")) {
200→        input.deps.sse.emitEvent(input.messageId, {
201→          type: "token",
202→          messageId: input.messageId,
203→          token: `${token} `,
204→        });
205→        await new Promise((resolve) => setTimeout(resolve, 25));
206→      }
207→    }
208→
209→    assistantSuggestions = sanitizeAssistantSuggestions(
210→      [...assistantSuggestions, ...unresolvedAssigneeSuggestions],
211→      3,
212→    );
213→
214→    const summaryBlock = buildExtractionComponentBlock(
215→      persistedEntities,
216→      persistedRelationships,
217→      input.deps.config.extractionDisplayThreshold,
218→    );
219→
220→    if (summaryBlock) {
221→      if (onboardingAfter === "complete") {
222→        const streamChunk = assistantText.length > 0 ? `\n\n${summaryBlock}` : summaryBlock;
223→        for (const token of streamChunk.split(" ")) {
224→          input.deps.sse.emitEvent(input.messageId, {
225→            type: "token",
226→            messageId: input.messageId,
227→            token: `${token} `,
228→          });
229→        }
230→      }
231→
232→      assistantText = assistantText.length > 0 ? `${assistantText}\n\n${summaryBlock}` : summaryBlock;
233→    }
234→
235→    if (assistantText.trim().length === 0) {
236→      assistantText = "I could not generate a response for that request.";
237→    }
238→
239→    const assistantMessageRecord = new RecordId("message", input.messageId);
240→    await input.deps.surreal.create(assistantMessageRecord).content({
241→      conversation: conversationRecord,
242→      role: "assistant",
243→      text: assistantText,
244→      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
245→      createdAt: now,
246→    });
247→
248→    await input.deps.surreal.update(conversationRecord).merge({
249→      updatedAt: now,
250→    });
251→
252→    void persistEmbeddings({
253→      surreal: input.deps.surreal,
254→      embeddingModel: input.deps.embeddingModel,
255→      embeddingDimension: input.deps.config.embeddingDimension,
256→      assistantMessageRecord,
257→      assistantText,
258→      entities: embeddingTargets,
259→    }).catch(() => undefined);
260→
261→    input.deps.sse.emitEvent(input.messageId, {
262→      type: "extraction",
263→      messageId: input.messageId,
264→      entities: persistedEntities,
265→      relationships: persistedRelationships,
266→    });
267→
268→    if (seedItems.length > 0) {
269→      input.deps.sse.emitEvent(input.messageId, {
270→        type: "onboarding_seed",
271→        messageId: input.messageId,
272→        seeds: seedItems,
273→      });
274→    }
275→
276→    if (onboardingBefore !== onboardingAfter) {
277→      input.deps.sse.emitEvent(input.messageId, {
278→        type: "onboarding_state",
279→        messageId: input.messageId,
280→        onboardingState: onboardingAfter,
281→      });
282→    }
283→
284→    input.deps.sse.emitEvent(input.messageId, {
285→      type: "assistant_message",
286→      messageId: input.messageId,
287→      text: assistantText,
288→      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
289→    });
290→
291→    input.deps.sse.emitEvent(input.messageId, {
292→      type: "done",
293→      messageId: input.messageId,
294→    });
295→
296→    logInfo("chat.message.process.execution.completed", "Chat message processing execution completed", {
297→      conversationId: input.conversationId,
298→      messageId: input.messageId,
299→      workspaceId: input.workspaceRecord.id as string,
300→      entityCount: persistedEntities.length,
301→      relationshipCount: persistedRelationships.length,
302→      seedCount: seedItems.length,
303→      durationMs: elapsedMs(startedAt),
304→    });
305→  } catch (error) {
306→    logError("chat.message.process.execution.failed", "Chat message processing execution failed", error, {
307→      conversationId: input.conversationId,
308→      messageId: input.messageId,
309→      workspaceId: input.workspaceRecord.id as string,
310→      durationMs: elapsedMs(startedAt),
311→    });
312→    const errorText = userFacingError(error, "chat processing failed");
313→    input.deps.sse.emitEvent(input.messageId, {
314→      type: "error",
315→      messageId: input.messageId,
316→      error: errorText,
317→    });
318→  }
319→}
320→
321→function sanitizeAssistantSuggestions(suggestions: string[], limit: number): string[] {
322→  return [...new Set(suggestions.map((value) => value.trim()))]
323→    .filter((value) => value.length > 0 && value.length <= 140)
324→    .slice(0, limit);
325→}
