 22→export async function persistExtractionOutput(input: {
 23→  surreal: Surreal;
 24→  embeddingModel: any;
 25→  embeddingDimension: number;
 26→  extractionModelId: string;
 27→  extractionStoreThreshold: number;
 28→  workspaceRecord: RecordId<"workspace", string>;
 29→  sourceRecord: SourceRecord;
 30→  sourceKind: SourceKind;
 31→  sourceLabel?: string;
 32→  promptText: string;
 33→  output: ExtractionPromptOutput;
 34→  sourceMessageRecord?: RecordId<"message", string>;
 35→  sourceChunkRecord?: RecordId<"document_chunk", string>;
 36→  extractionHistoryMessageIds?: string[];
 37→  now: Date;
 38→}): Promise<PersistExtractionResult> {
 39→  const startedAt = performance.now();
 40→  logInfo("extraction.persist.started", "Extraction persistence started", {
 41→    workspaceId: input.workspaceRecord.id as string,
 42→    sourceKind: input.sourceKind,
 43→    sourceId: input.sourceRecord.id as string,
 44→    candidateEntityCount: input.output.entities.length,
 45→    candidateRelationshipCount: input.output.relationships.length,
 46→  });
 47→
 48→  try {
 49→    const entities = postValidateEntities({
 50→      entities: input.output.entities,
 51→      sourceText: input.promptText,
 52→      storeThreshold: input.extractionStoreThreshold,
 53→    });
 54→    if (input.sourceKind === "message" && !input.sourceMessageRecord) {
 55→      throw new Error("message extraction persistence requires sourceMessageRecord");
 56→    }
 57→
 58→    const extractionHistoryMessageIds = new Set(input.extractionHistoryMessageIds ?? []);
 59→    const relationships = postValidateRelationships({
 60→      relationships: input.output.relationships,
 61→      storeThreshold: input.extractionStoreThreshold,
 62→    }).map((relationship) => ({
 63→      ...relationship,
 64→      kind: normalizeRelationshipKind(relationship.kind),
 65→    }));
 66→
 67→    const persistedEntities: ExtractedEntity[] = [];
 68→    const persistedRelationships: ExtractedRelationship[] = [];
 69→    const seeds: OnboardingSeedItem[] = [];
 70→    const embeddingTargets: Array<{ record: GraphEntityRecord; text: string }> = [];
 71→    const entityByTempId = new Map<string, TempEntityReference>();
 72→    const unresolvedAssigneeNames = new Set<string>();
 73→
 74→    const workspaceProjects = await loadWorkspaceProjects(input.surreal, input.workspaceRecord);
 75→
 76→    for (const extracted of entities) {
 77→      const resolvedFromMessageId = resolveValidatedResolvedFromMessageId({
 78→        resolvedFromMessageId: "resolvedFromMessageId" in extracted ? extracted.resolvedFromMessageId : undefined,
 79→        sourceKind: input.sourceKind,
 80→        sourceMessageId: input.sourceMessageRecord?.id as string | undefined,
 81→        extractionHistoryMessageIds,
 82→      });
 83→      const resolvedFromMessageRecord = resolvedFromMessageId
 84→        ? new RecordId("message", resolvedFromMessageId)
 85→        : undefined;
 86→
 87→      const persisted = await upsertGraphEntity({
 88→        surreal: input.surreal,
 89→        embeddingModel: input.embeddingModel,
 90→        embeddingDimension: input.embeddingDimension,
 91→        extractionModelId: input.extractionModelId,
 92→        workspaceRecord: input.workspaceRecord,
 93→        workspaceProjects,
 94→        sourceRecord: input.sourceRecord,
 95→        sourceKind: input.sourceKind,
 96→        promptText: input.promptText,
 97→        extracted: extracted as ExtractionPromptEntity & { kind: Exclude<EntityKind, "workspace" | "person"> },
 98→        sourceMessageRecord: input.sourceMessageRecord,
 99→        sourceChunkRecord: input.sourceChunkRecord,
100→        resolvedFromMessageRecord,
101→        now: input.now,
102→      });
103→
104→      entityByTempId.set(extracted.tempId, {
105→        record: persisted.record,
106→        text: persisted.text,
107→        id: persisted.record.id as string,
108→        kind: persisted.kind,
109→      });
110→
111→      persistedEntities.push({
112→        id: persisted.record.id as string,
113→        kind: persisted.kind,
114→        text: persisted.text,
115→        confidence: extracted.confidence,
116→        sourceKind: input.sourceKind,
117→        sourceId: input.sourceRecord.id as string,
118→      });
119→
120→      seeds.push({
121→        id: persisted.record.id as string,
122→        kind: persisted.kind,
123→        text: persisted.text,
124→        confidence: extracted.confidence,
125→        sourceKind: input.sourceKind,
126→        sourceId: input.sourceRecord.id as string,
127→        ...(input.sourceLabel ? { sourceLabel: input.sourceLabel } : {}),
128→      });
129→
130→      if (persisted.created) {
131→        embeddingTargets.push({
132→          record: persisted.record,
133→          text: persisted.text,
134→        });
135→      }
136→
137→      const assigneeName = "assignee_name" in extracted ? extracted.assignee_name : undefined;
138→      if (assigneeName) {
139→        const attribution = await applyAssigneeReference({
140→          surreal: input.surreal,
141→          workspaceRecord: input.workspaceRecord,
142→          entityRecord: persisted.record,
143→          entityKind: persisted.kind,
144→          assigneeName,
145→          now: input.now,
146→        });
147→
148→        if (!attribution.resolved) {
149→          unresolvedAssigneeNames.add(attribution.assigneeName);
150→        }
151→      }
152→    }
153→
154→    for (const relationship of relationships) {
155→      const from = entityByTempId.get(relationship.fromTempId);
156→      const to = entityByTempId.get(relationship.toTempId);
157→      if (!from || !to) {
158→        continue;
159→      }
160→
161→      const relationRecord = new RecordId("entity_relation", randomUUID());
162→      await input.surreal.relate(from.record, relationRecord, to.record, {
163→        kind: relationship.kind,
164→        confidence: relationship.confidence,
165→        ...(input.sourceMessageRecord ? { source_message: input.sourceMessageRecord } : {}),
166→        ...(input.sourceChunkRecord ? { source_chunk: input.sourceChunkRecord } : {}),
167→        extracted_at: input.now,
168→        created_at: input.now,
169→        from_text: relationship.fromText,
170→        to_text: relationship.toText,
171→      }).output("after");
172→
173→      persistedRelationships.push({
174→        id: relationRecord.id as string,
175→        kind: relationship.kind,
176→        fromId: from.id,
177→        toId: to.id,
178→        confidence: relationship.confidence,
179→        sourceKind: input.sourceKind,
180→        sourceId: input.sourceRecord.id as string,
181→        ...(input.sourceMessageRecord ? { sourceMessageId: input.sourceMessageRecord.id as string } : {}),
182→        fromText: relationship.fromText,
183→        toText: relationship.toText,
184→      });
185→    }
186→
187→    logInfo("extraction.persist.completed", "Extraction persistence completed", {
188→      workspaceId: input.workspaceRecord.id as string,
189→      sourceKind: input.sourceKind,
190→      sourceId: input.sourceRecord.id as string,
191→      persistedEntityCount: persistedEntities.length,
192→      persistedRelationshipCount: persistedRelationships.length,
193→      seedCount: seeds.length,
194→      toolCount: input.output.tools.length,
195→      unresolvedAssigneeCount: unresolvedAssigneeNames.size,
196→      durationMs: elapsedMs(startedAt),
197→    });
198→
199→    return {
200→      entities: persistedEntities,
201→      relationships: persistedRelationships,
202→      seeds,
203→      embeddingTargets,
204→      tools: input.output.tools.map((tool) => tool.trim()).filter((tool) => tool.length > 0),
205→      unresolvedAssigneeNames: [...unresolvedAssigneeNames],
206→    };
207→  } catch (error) {
208→    logError("extraction.persist.failed", "Extraction persistence failed", error, {
209→      workspaceId: input.workspaceRecord.id as string,
210→      sourceKind: input.sourceKind,
211→      sourceId: input.sourceRecord.id as string,
212→      durationMs: elapsedMs(startedAt),
213→    });
214→    throw error;
215→  }
216→}
