306→export async function appendExtractedTools(
307→  surreal: Surreal,
308→  workspaceRecord: RecordId<"workspace", string>,
309→  extractedTools: string[],
310→  now: Date,
311→): Promise<void> {
312→  const dedupedTools = [...new Set(extractedTools.map((tool) => tool.trim()).filter((tool) => tool.length > 0))];
313→  if (extractedTools.length > 0 && dedupedTools.length > 0) {
314→    await appendWorkspaceTools(surreal, workspaceRecord, dedupedTools, now);
315→  }
316→}
