161→async function parseIncomingAttachment(file: File): Promise<IncomingAttachment> {
162→  if (file.size > MAX_UPLOAD_BYTES) {
163→    throw new HttpError(400, `file is too large, max size is ${MAX_UPLOAD_BYTES} bytes`);
164→  }
165→
166→  const extension = file.name.split(".").pop()?.toLowerCase();
167→  if (!extension || !allowedUploadExtensions.has(extension)) {
168→    throw new HttpError(400, "only .md and .txt files are supported in phase 1");
169→  }
170→
171→  const content = (await file.text()).trim();
172→  if (content.length === 0) {
173→    throw new HttpError(400, "uploaded file content is empty");
174→  }
175→
176→  return {
177→    fileName: file.name,
178→    mimeType: file.type.trim().length > 0 ? file.type : "text/plain",
179→    sizeBytes: file.size,
180→    content,
181→  };
182→}
