 63→export async function createEmbedding(
 64→  embeddingModel: any,
 65→  embeddingDimension: number,
 66→  value: string,
 67→): Promise<number[] | undefined> {
 68→  const normalized = value.trim();
 69→  if (normalized.length === 0) {
 70→    return undefined;
 71→  }
 72→
 73→  const result = await embed({
 74→    model: embeddingModel,
 75→    value: normalized,
 76→  });
 77→
 78→  if (result.embedding.length !== embeddingDimension) {
 79→    logWarn("embedding.dimension_mismatch", "Skipping embedding write due to vector dimension mismatch", {
 80→      actualDimension: result.embedding.length,
 81→      configuredDimension: embeddingDimension,
 82→    });
 83→    return undefined;
 84→  }
 85→
 86→  return result.embedding;
 87→}
 88→
 89→async function writeEmbedding(input: {
 90→  surreal: Surreal;
 91→  record: RecordId<string, string>;
 92→  embedding: number[];
 93→  label: string;
 94→}): Promise<void> {
 95→  const [updateResult] = await input.surreal
 96→    .query<[unknown]>(
 97→      "UPDATE $record MERGE $patch RETURN AFTER;",
 98→      {
 99→        record: input.record,
100→        patch: { embedding: input.embedding },
101→      },
102→    )
103→    .collect<[unknown]>();
104→
105→  if (queryResultHasRecordId(updateResult)) {
106→    return;
107→  }
108→
109→  const verified = await verifyEmbeddingPresent(input.surreal, input.record, input.embedding.length);
110→  if (!verified) {
111→    throw new Error(`${input.label} embedding update verification failed`);
112→  }
113→
114→  logWarn(
115→    "embedding.persist.unexpected_update_output",
116→    "embedding update returned no row but verification succeeded",
117→    { record: input.label },
118→  );
119→}
120→
121→async function verifyEmbeddingPresent(
122→  surreal: Surreal,
123→  record: RecordId<string, string>,
124→  expectedDimension: number,
125→): Promise<boolean> {
126→  const [queryResult] = await surreal
127→    .query<[unknown]>("SELECT id, embedding FROM $record;", { record })
128→    .collect<[unknown]>();
129→  const row = extractRecordFromPayload(queryResult);
130→  if (!row || row.id === undefined) {
131→    return false;
132→  }
133→
134→  const vectorLength = readVectorLength(row.embedding);
135→  return vectorLength === expectedDimension;
136→}
137→
138→function queryResultHasRecordId(result: unknown): boolean {
139→  return flattenQueryResult(result).some((candidate) => {
140→    if (!candidate || typeof candidate !== "object" || !("id" in candidate)) {
141→      return false;
142→    }
143→    return (candidate as { id?: unknown }).id !== undefined;
144→  });
145→}
146→
147→function extractRecordFromPayload(value: unknown):
148→  | { id?: unknown; embedding?: unknown }
149→  | undefined {
150→  const candidates = flattenQueryResult(value).filter((entry) => entry && typeof entry === "object");
151→  const withId = candidates.find((entry) => "id" in (entry as Record<string, unknown>));
152→  if (withId) {
153→    return withId as { id?: unknown; embedding?: unknown };
154→  }
155→
156→  const first = candidates[0];
157→  return first ? (first as { id?: unknown; embedding?: unknown }) : undefined;
158→}
159→
160→function flattenQueryResult(value: unknown): unknown[] {
161→  if (!Array.isArray(value)) {
162→    return [value];
163→  }
164→
165→  const flattened: unknown[] = [];
166→  for (const entry of value) {
167→    if (Array.isArray(entry)) {
168→      flattened.push(...flattenQueryResult(entry));
169→      continue;
170→    }
171→    flattened.push(entry);
172→  }
173→
174→  return flattened;
175→}
176→
177→function readVectorLength(value: unknown): number | undefined {
178→  if (Array.isArray(value)) {
179→    return value.length;
180→  }
181→
182→  if (ArrayBuffer.isView(value)) {
183→    const arrayLike = value as { length?: number };
184→    if (typeof arrayLike.length === "number") {
185→      return arrayLike.length;
186→    }
187→  }
188→
189→  if (value && typeof value === "object" && Symbol.iterator in value) {
190→    const iterator = (value as { [Symbol.iterator]?: () => Iterator<unknown> })[Symbol.iterator];
191→    if (typeof iterator === "function") {
192→      return [...(value as Iterable<unknown>)].length;
193→    }
194→  }
195→
196→  return undefined;
197→}
