459→export function normalizeRelationshipKind(value: string): string {
460→  return value
461→    .trim()
462→    .replace(/[^a-zA-Z0-9]+/g, "_")
463→    .replace(/_+/g, "_")
464→    .replace(/^_/, "")
465→    .replace(/_$/, "")
466→    .toUpperCase();
467→}
468→
469→function cosineSimilarity(a: number[], b: number[]): number {
470→  if (a.length !== b.length) {
471→    return -1;
472→  }
473→
474→  let dot = 0;
475→  let normA = 0;
476→  let normB = 0;
477→
478→  for (let i = 0; i < a.length; i += 1) {
479→    dot += a[i] * b[i];
480→    normA += a[i] * a[i];
481→    normB += b[i] * b[i];
482→  }
483→
484→  if (normA === 0 || normB === 0) {
485→    return -1;
486→  }
487→
488→  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
489→}
