 10→export async function ingestAttachment(input: {
 11→  surreal: Surreal;
 12→  extractionModel: any;
 13→  embeddingModel: any;
 14→  embeddingDimension: number;
 15→  extractionStoreThreshold: number;
 16→  extractionModelId: string;
 17→  workspaceRecord: RecordId<"workspace", string>;
 18→  conversationRecord: RecordId<"conversation", string>;
 19→  userMessageRecord: RecordId<"message", string>;
 20→  attachment: IncomingAttachment;
 21→  now: Date;
 22→}): Promise<PersistExtractionResult> {
 23→  const startedAt = performance.now();
 24→  const documentRecord = new RecordId("document", randomUUID());
 25→  const workspaceId = input.workspaceRecord.id as string;
 26→  const conversationId = input.conversationRecord.id as string;
 27→
 28→  logInfo("attachment.ingest.started", "Attachment ingestion started", {
 29→    workspaceId,
 30→    conversationId,
 31→    documentId: documentRecord.id as string,
 32→    fileSizeBytes: input.attachment.sizeBytes,
 33→  });
 34→
 35→  try {
 36→    await input.surreal.create(documentRecord).content({
 37→      workspace: input.workspaceRecord,
 38→      name: input.attachment.fileName,
 39→      mime_type: input.attachment.mimeType,
 40→      size_bytes: input.attachment.sizeBytes,
 41→      uploaded_at: input.now,
 42→    });
 43→
 44→    const chunks = splitDocumentIntoChunks(input.attachment.content);
 45→    const persistedEntities = [];
 46→    const persistedRelationships = [];
 47→    const seeds = [];
 48→    const embeddingTargets = [];
 49→    const tools = [];
 50→    const unresolvedAssigneeNames = [];
 51→
 52→    for (const chunk of chunks) {
 53→      const chunkRecord = new RecordId("document_chunk", randomUUID());
 54→      const chunkEmbedding = await createEmbedding(input.embeddingModel, input.embeddingDimension, chunk.content);
 55→
 56→      await input.surreal.create(chunkRecord).content({
 57→        document: documentRecord,
 58→        workspace: input.workspaceRecord,
 59→        content: chunk.content,
 60→        ...(chunk.heading ? { section_heading: chunk.heading } : {}),
 61→        position: chunk.position,
 62→        ...(chunkEmbedding ? { embedding: chunkEmbedding } : {}),
 63→        created_at: input.now,
 64→      });
 65→
 66→      const extraction = await extractStructuredGraph({
 67→        extractionModel: input.extractionModel,
 68→        conversationHistory: [],
 69→        graphContext: [],
 70→        sourceText: chunk.content,
 71→        onboarding: true,
 72→        heading: chunk.heading,
 73→      });
 74→
 75→      const result = await persistExtractionOutput({
 76→        surreal: input.surreal,
 77→        embeddingModel: input.embeddingModel,
 78→        embeddingDimension: input.embeddingDimension,
 79→        extractionModelId: input.extractionModelId,
 80→        extractionStoreThreshold: input.extractionStoreThreshold,
 81→        workspaceRecord: input.workspaceRecord,
 82→        sourceRecord: chunkRecord as SourceRecord,
 83→        sourceKind: "document_chunk",
 84→        sourceLabel: chunk.heading ? `${input.attachment.fileName} · ${chunk.heading}` : input.attachment.fileName,
 85→        promptText: chunk.content,
 86→        output: extraction,
 87→        sourceChunkRecord: chunkRecord,
 88→        now: input.now,
 89→      });
 90→
 91→      persistedEntities.push(...result.entities);
 92→      persistedRelationships.push(...result.relationships);
 93→      seeds.push(...result.seeds);
 94→      embeddingTargets.push(...result.embeddingTargets);
 95→      tools.push(...result.tools);
 96→      unresolvedAssigneeNames.push(...result.unresolvedAssigneeNames);
 97→    }
 98→
 99→    logInfo("attachment.ingest.completed", "Attachment ingestion completed", {
100→      workspaceId,
101→      conversationId,
102→      documentId: documentRecord.id as string,
103→      entityCount: persistedEntities.length,
104→      relationshipCount: persistedRelationships.length,
105→      chunkCount: chunks.length,
106→      durationMs: elapsedMs(startedAt),
107→    });
108→
109→    return {
110→      entities: persistedEntities,
111→      relationships: persistedRelationships,
112→      seeds,
113→      embeddingTargets,
114→      tools,
115→      unresolvedAssigneeNames,
116→    };
117→  } catch (error) {
118→    logError("attachment.ingest.failed", "Attachment ingestion failed", error, {
119→      workspaceId,
120→      conversationId,
121→      documentId: documentRecord.id as string,
122→      durationMs: elapsedMs(startedAt),
123→    });
124→    throw error;
125→  }
126→}
