  1→import { RecordId, type Surreal } from "surrealdb";
  2→import { readEntityText } from "./entity-text";
  3→import type {
  4→  ConversationProvenanceRow,
  5→  ExtractionConversationContext,
  6→  ExtractionGraphContextRow,
  7→  MessageContextRow,
  8→} from "./types";
  9→
 10→type ExtractableEntityKind = "project" | "person" | "feature" | "task" | "decision" | "question";
 11→
 12→export async function loadAssistantConversationContext(
 13→  surreal: Surreal,
 14→  conversationId: string,
 15→): Promise<MessageContextRow[]> {
 16→  const conversationRecord = new RecordId("conversation", conversationId);
 17→  const [rows] = await surreal
 18→    .query<[MessageContextRow[]]>(
 19→      "RETURN fn::conversation_recent($conversation, $limit);",
 20→      {
 21→        conversation: conversationRecord,
 22→        limit: 10,
 23→      },
 24→    )
 25→    .collect<[MessageContextRow[]]>();
 26→
 27→  return [...rows].reverse();
 28→}
 29→
 30→export async function loadExtractionConversationContext(input: {
 31→  surreal: Surreal;
 32→  conversationId: string;
 33→  currentMessageRecord: RecordId<"message", string>;
 34→}): Promise<ExtractionConversationContext> {
 35→  const conversationRecord = new RecordId("conversation", input.conversationId);
 36→  const [rows] = await input.surreal
 37→    .query<[MessageContextRow[]]>(
 38→      "RETURN fn::conversation_recent($conversation, $limit);",
 39→      {
 40→        conversation: conversationRecord,
 41→        limit: 31,
 42→      },
 43→    )
 44→    .collect<[MessageContextRow[]]>();
 45→
 46→  const ordered = [...rows].reverse();
 47→  const currentMessage = ordered.find((row) => row.id.id === input.currentMessageRecord.id);
 48→  if (!currentMessage) {
 49→    throw new Error(`current message not found in conversation context: ${input.currentMessageRecord.id as string}`);
 50→  }
 51→
 52→  return {
 53→    conversationHistory: ordered.filter((row) => row.id.id !== input.currentMessageRecord.id).slice(-30),
 54→    currentMessage,
 55→  };
 56→}
 57→
 58→export async function loadConversationGraphContext(
 59→  surreal: Surreal,
 60→  conversationId: string,
 61→  limit: number,
 62→): Promise<ExtractionGraphContextRow[]> {
 63→  const conversationRecord = new RecordId("conversation", conversationId);
 64→  const [rows] = await surreal
 65→    .query<[ConversationProvenanceRow[]]>(
 66→      [
 67→        "SELECT `in`, out, confidence, extracted_at",
 68→        "FROM extraction_relation",
 69→        "WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation = $conversation)",
 70→        "ORDER BY extracted_at DESC",
 71→        "LIMIT $limit;",
 72→      ].join(" "),
 73→      { conversation: conversationRecord, limit },
 74→    )
 75→    .collect<[ConversationProvenanceRow[]]>();
 76→
 77→  const seen = new Set<string>();
 78→  const items: ExtractionGraphContextRow[] = [];
 79→
 80→  for (const row of rows) {
 81→    const entityId = row.out.id as string;
 82→    if (seen.has(entityId)) {
 83→      continue;
 84→    }
 85→
 86→    const entityTable = row.out.tb;
 87→    if (
 88→      entityTable !== "project" &&
 89→      entityTable !== "person" &&
 90→      entityTable !== "feature" &&
 91→      entityTable !== "task" &&
 92→      entityTable !== "decision" &&
 93→      entityTable !== "question"
 94→    ) {
 95→      continue;
 96→    }
 97→
 98→    const entityText = await readEntityText(surreal, row.out);
 99→    if (!entityText) {
100→      continue;
101→    }
102→
103→    items.push({
104→      id: row.out,
105→      kind: entityTable as ExtractableEntityKind,
106→      text: entityText,
107→      confidence: row.confidence,
108→      sourceMessage: row.in,
109→    });
110→    seen.add(entityId);
111→  }
112→
113→  return items;
114→}
