   3→// ## Enumeration
   4→
   5→/**
   6→ * How phrasing content is aligned
   7→ * ({@link https://drafts.csswg.org/css-text/ | [CSSTEXT]}).
   8→ *
   9→ * * `'left'`: See the
  10→ *   {@link https://drafts.csswg.org/css-text/#valdef-text-align-left | left}
  11→ *   value of the `text-align` CSS property
  12→ * * `'right'`: See the
  13→ *   {@link https://drafts.csswg.org/css-text/#valdef-text-align-right | right}
  14→ *   value of the `text-align` CSS property
  15→ * * `'center'`: See the
  16→ *   {@link https://drafts.csswg.org/css-text/#valdef-text-align-center | center}
  17→ *   value of the `text-align` CSS property
  18→ * * `null`: phrasing content is aligned as defined by the host environment
  19→ *
  20→ * Used in GFM tables.
  21→ */
  22→export type AlignType = "center" | "left" | "right" | null;
  23→
  24→/**
  25→ * Explicitness of a reference.
  26→ *
  27→ * `'shortcut'`: the reference is implicit, its identifier inferred from its
  28→ *   content
  29→ * `'collapsed'`: the reference is explicit, its identifier inferred from its
  30→ *   content
  31→ * `'full'`: the reference is explicit, its identifier explicitly set
  32→ */
  33→export type ReferenceType = "shortcut" | "collapsed" | "full";
  34→
  35→// ## Mixin
  36→
  37→/**
  38→ * Node with a fallback.
  39→ */
  40→export interface Alternative {
  41→    /**
  42→     * Equivalent content for environments that cannot represent the node as
  43→     * intended.
  44→     */
  45→    alt?: string | null | undefined;
  46→}
  47→
  48→/**
  49→ * Internal relation from one node to another.
  50→ *
  51→ * Whether the value of `identifier` is expected to be a unique identifier or
  52→ * not depends on the type of node including the Association.
  53→ * An example of this is that they should be unique on {@link Definition},
  54→ * whereas multiple {@link LinkReference}s can be non-unique to be associated
  55→ * with one definition.
  56→ */
  57→export interface Association {
  58→    /**
  59→     * Relation of association.
  60→     *
  61→     * `identifier` is a source value: character escapes and character
  62→     * references are not parsed.
  63→     *
  64→     * It can match another node.
  65→     *
  66→     * Its value must be normalized.
  67→     * To normalize a value, collapse markdown whitespace (`[\t\n\r ]+`) to a space,
  68→     * trim the optional initial and/or final space, and perform Unicode-aware
  69→     * case-folding.
  70→     */
  71→    identifier: string;
  72→
  73→    /**
  74→     * Relation of association, in parsed form.
  75→     *
  76→     * `label` is a `string` value: it works just like `title` on {@link Link}
  77→     * or a `lang` on {@link Code}: character escapes and character references
  78→     * are parsed.
  79→     *
  80→     * It can match another node.
  81→     */
  82→    label?: string | null | undefined;
  83→}
  84→
  85→/**
  86→ * Marker that is associated to another node.
  87→ */
  88→export interface Reference extends Association {
  89→    /**
  90→     * Explicitness of the reference.
  91→     */
  92→    referenceType: ReferenceType;
  93→}
  94→
  95→/**
  96→ * Reference to resource.
  97→ */
  98→export interface Resource {
  99→    /**
 100→     * URL to the referenced resource.
 101→     */
 102→    url: string;
 103→    /**
 104→     * Advisory information for the resource, such as would be appropriate for
 105→     * a tooltip.
 106→     */
 107→    title?: string | null | undefined;
 108→}
