 1→import { describe, expect, it } from "bun:test";
 2→import { randomUUID } from "node:crypto";
 3→import { RecordId } from "surrealdb";
 4→import { collectSseEvents, fetchJson, setupSmokeSuite } from "./smoke-test-kit";
 5→
 6→type StreamEvent =
 7→  | { type: "assistant_message"; messageId: string; text: string }
 8→  | { type: "done"; messageId: string }
 9→  | { type: "error"; messageId: string; error: string }
10→  | { type: string; messageId: string };
11→
12→const getRuntime = setupSmokeSuite("readme_import");
13→
14→describe("README import smoke", () => {
15→  it("ingests README.md and persists document chunks", async () => {
16→    const { baseUrl, surreal } = getRuntime();
17→
18→    const readmeText = await Bun.file(new URL("../../README.md", import.meta.url)).text();
19→    expect(readmeText.trim().length).toBeGreaterThan(0);
20→
21→    const create = await fetchJson<{ workspaceId: string; conversationId: string }>(`${baseUrl}/api/workspaces`, {
22→      method: "POST",
23→      headers: { "Content-Type": "application/json" },
24→      body: JSON.stringify({
25→        name: `README Smoke ${Date.now()}`,
26→        ownerDisplayName: "README Smoke Owner",
27→      }),
28→    });
29→
30→    const workspaceRecord = new RecordId("workspace", create.workspaceId);
31→
32→    const uploadForm = new FormData();
33→    uploadForm.set("clientMessageId", randomUUID());
34→    uploadForm.set("workspaceId", create.workspaceId);
35→    uploadForm.set("conversationId", create.conversationId);
36→    uploadForm.set("text", "Importing README.md for smoke validation.");
37→    uploadForm.set("file", new File([readmeText], "README.md", { type: "text/markdown" }));
38→
39→    const uploadResponse = await fetchJson<{ streamUrl: string }>(`${baseUrl}/api/chat/messages`, {
40→      method: "POST",
41→      body: uploadForm,
42→    });
43→
44→    const events = await collectSseEvents<StreamEvent>(`${baseUrl}${uploadResponse.streamUrl}`, 120_000);
45→    expect(events.some((event) => event.type === "assistant_message")).toBe(true);
46→    expect(events.some((event) => event.type === "done")).toBe(true);
47→
48→    const [documentRows] = await surreal
49→      .query<[Array<{ id: RecordId<"document", string> }>]>(
50→        "SELECT id FROM document WHERE workspace = $workspace AND name = $name ORDER BY uploaded_at DESC LIMIT 1;",
51→        {
52→          workspace: workspaceRecord,
53→          name: "README.md",
54→        },
55→      )
56→      .collect<[Array<{ id: RecordId<"document", string> }>]>();
57→
58→    expect(documentRows.length).toBeGreaterThan(0);
59→    const documentRecord = documentRows[0];
60→    if (!documentRecord) {
61→      throw new Error("README.md document record was not created");
62→    }
63→
64→    const [chunkRows] = await surreal
65→      .query<[Array<{ id: RecordId<"document_chunk", string> }>]>(
66→        "SELECT id FROM document_chunk WHERE document = $document LIMIT 1;",
67→        {
68→          document: documentRecord.id,
69→        },
70→      )
71→      .collect<[Array<{ id: RecordId<"document_chunk", string> }>]>();
72→
73→    expect(chunkRows.length).toBeGreaterThan(0);
74→  }, 150_000);
75→});
